import React, { useState } from 'react';
import { submenus } from './submenus';
import { useNavigate, useLocation } from 'react-router-dom';

const itens = [
  { label: 'SCM', icon: '📡' },
  { label: 'TVpA', icon: '📺' },
  { label: 'STFC', icon: '☎️' },
  { label: 'RELATÓRIO ECONÔMICO', icon: '📊' },
  { label: 'INFRA', icon: '🏗️' },
  { label: 'POSTES', icon: '🪵' },
  { label: 'GERENCIADOR', icon: '👤' },
  { label: 'FINANCEIRO', icon: '💲' },
  { label: 'CONTRATOS E CERTIDÕES', icon: '📄' },
];

const MenuLateral = ({ voltarLink, clienteInfo }) => {
  const [submenuAberto, setSubmenuAberto] = useState(null);
  const navigate = useNavigate();


  const handleMouseEnter = (label) => {
    if (submenus[label]) setSubmenuAberto(label);
  };
  // Só fecha o submenu se não for STFC
  const handleMouseLeave = () => {
    if (submenuAberto !== 'STFC') setSubmenuAberto(null);
  };

  // Busca id do cliente selecionado na URL (query ou rota)
  const location = useLocation();
  const search = location.search;
  const params = new URLSearchParams(search);
  let idCliente = params.get('id');
  if (!idCliente) {
    // Tenta extrair da rota tipo /cliente/:id
    const match = location.pathname.match(/cliente\/(\d+)/);
    if (match) idCliente = match[1];
  }

  const handleSubmenuClick = (itemLabel, subLabel) => {
    if (itemLabel === 'SCM' && subLabel === 'Novo Relatório') {
      // Sempre tenta obter o idCliente da URL
      let id = idCliente;
      if (!id) {
        const match = location.pathname.match(/cliente\/(\d+)/);
        if (match && match[1]) id = match[1];
      }
      navigate(`/scm/cadastro${id ? `?id=${id}` : ''}`);
    } else if (itemLabel === 'SCM' && subLabel === 'ACOMPANHAMENTO SCM') {
      // Sempre tenta obter o idCliente da URL
      let id = idCliente;
      if (!id) {
        const match = location.pathname.match(/cliente\/(\d+)/);
        if (match && match[1]) id = match[1];
      }
      navigate(`/scm/cadastro${id ? `?id=${id}&aba=acompanhamento` : '?aba=acompanhamento'}`);
    } else if (itemLabel === 'TVpA' && subLabel === 'Novo Relatório') {
      // Busca o CNPJ do cliente na URL, se houver
      let cnpj = params.get('cnpj');
      if (!cnpj && window.location.pathname.match(/cliente\/(\d+)/)) {
        const cnpjInput = document.querySelector('input[name="cnpj"]');
        if (cnpjInput && cnpjInput.value) {
          cnpj = cnpjInput.value;
        }
      }
      if (cnpj) {
        cnpj = cnpj.replace(/[\.\/-]/g, '');
        navigate(`/tvpa/cadastro?cnpj=${cnpj}`);
      } else {
        navigate('/tvpa/cadastro');
      }
    } else if (itemLabel === 'TVpA' && subLabel === 'ACOMPANHAMENTO TVpA') {
      navigate('/tvpa/acompanhamento');
    } else if (itemLabel === 'STFC' && subLabel === 'Novo Relatório STFC') {
      let cnpj = params.get('cnpj');
      if (!cnpj && window.location.pathname.match(/cliente\/(\d+)/)) {
        const cnpjInput = document.querySelector('input[name="cnpj"]');
        if (cnpjInput && cnpjInput.value) {
          cnpj = cnpjInput.value;
        }
      }
      if (cnpj) {
        cnpj = cnpj.replace(/[\.\/-]/g, '');
        navigate(`/stfc/cadastro?cnpj=${cnpj}`);
      } else {
        navigate('/stfc/cadastro');
      }
    } else if (itemLabel === 'STFC' && subLabel === 'ACOMPANHAMENTO STFC') {
      navigate('/stfc/acompanhamento');
    } else if (itemLabel === 'RELATÓRIO ECONÔMICO' && subLabel === 'NOVO RELATORIO PRIMEIRO SEMESTRE') {
      navigate('/relatorio-economico/primeiro-semestre');
    } else if (itemLabel === 'RELATÓRIO ECONÔMICO' && subLabel === 'NOVO RELATORIO SEGUNDO SEMESTRE') {
      navigate('/relatorio-economico/segundo-semestre');
    } else if (itemLabel === 'RELATÓRIO ECONÔMICO' && subLabel === 'ACOMPANHAMENTO RELATORIO ECONOMICO') {
      navigate('/relatorio-economico/acompanhamento');
    } else if (itemLabel === 'INFRA' && subLabel === 'Estações') {
      navigate('/infra/estacoes');
    } else {
      alert(`Clicou em ${subLabel}`);
    }
  };

  return (
    <aside style={{
      width: 200,
      background: '#111',
      color: '#fff',
      minHeight: '100vh',
      position: 'fixed',
      left: 0,
      top: 0,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      paddingTop: 12,
      zIndex: 10
    }}>
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        width: 200,
        minHeight: 120,
        background: '#111',
        zIndex: 200,
        paddingTop: 0,
        textAlign: 'center',
        boxShadow: '0 2px 8px #0002',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        paddingBottom: 8
      }}>
        <div style={{width:'100%', display:'flex', justifyContent:'flex-start', alignItems:'center', padding:'8px 0 0 12px'}}>
          {voltarLink}
        </div>
        <div style={{marginTop: 4, fontWeight: 600, fontSize: 15}}>Bem vindo!</div>
        <div style={{marginTop: 2, fontSize: 14}}>{clienteInfo}</div>
      </div>
      <div style={{marginBottom: 32, textAlign: 'center', marginTop: 110}}>
      </div>
      <nav style={{width: '100%'}}>
        {(() => {
          const rotasPrincipais = {
            'SCM': '/scm',
            'TVpA': '/tvpa',
            'STFC': '/stfc',
            'RELATÓRIO ECONÔMICO': '/relatorio-economico',
            'INFRA': '/infra',
            'POSTES': '/postes',
            'GERENCIADOR': '/gerenciador',
            'FINANCEIRO': '/financeiro',
            'CONTRATOS E CERTIDÕES': '/contratos',
          };
          return itens.map(item => {
            const rota = rotasPrincipais[item.label];
            const ativo = rota && location.pathname.startsWith(rota);
            return (
              <div
                key={item.label}
                style={{
                  position: 'relative',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 12,
                  padding: '12px 24px',
                  cursor: 'pointer',
                  color: ativo ? '#FFD600' : '#fff',
                  fontWeight: ativo ? 'bold' : 'normal',
                  fontSize: 16,
                  transition: 'background 0.2s',
                  background: submenuAberto === item.label ? '#222' : 'none',
                }}
                onMouseEnter={() => handleMouseEnter(item.label)}
                onMouseLeave={handleMouseLeave}
                onClick={() => {
                  if (item.label === 'STFC') setSubmenuAberto('STFC');
                }}
              >
                <span style={{fontSize: 20}}>{item.icon}</span>
                <span>{item.label}</span>
                {/* Submenu */}
                {submenuAberto === item.label && submenus[item.label] && (
                  <div
                    style={{
                      position: 'absolute',
                      left: '100%',
                      top: 0,
                      background: '#222',
                      color: '#fff',
                      minWidth: 180,
                      borderRadius: 8,
                      boxShadow: '2px 2px 8px #0003',
                      padding: '8px 0',
                      zIndex: 50,
                    }}
                    onMouseEnter={() => setSubmenuAberto(item.label)}
                    onMouseLeave={handleMouseLeave}
                  >
                    {submenus[item.label].map(sub => (
                      <div
                        key={sub.label}
                        style={{
                          padding: '8px 20px',
                          cursor: 'pointer',
                          fontSize: 15,
                          whiteSpace: 'nowrap',
                          transition: 'background 0.2s',
                          color: '#fff',
                        }}
                        onClick={() => handleSubmenuClick(item.label, sub.label)}
                      >
                        {sub.label}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            );
          });
        })()}
        
      </nav>
    </aside>
  );
};

export default MenuLateral;
